/* HealingMart Calculator Core v1.1.0 */
(function (w) {
  "use strict";
  const modules = Object.create(null);
  const mounted = new WeakMap();

  function parseNumber(value) {
    const n = Number(String(value ?? "").replace(/,/g, "").trim());
    return Number.isFinite(n) ? n : NaN;
  }
  function formatNumber(value, maximumFractionDigits = 2) {
    if (!Number.isFinite(value)) return "-";
    return new Intl.NumberFormat("ko-KR", { maximumFractionDigits }).format(value);
  }
  function formatWon(value) {
    return formatNumber(Math.round(value), 0) + "원";
  }
  function localDateString(date = new Date()) {
    const y = date.getFullYear();
    const m = String(date.getMonth() + 1).padStart(2, "0");
    const d = String(date.getDate()).padStart(2, "0");
    return `${y}-${m}-${d}`;
  }
  function dateFromLocalInput(value) {
    if (!/^\d{4}-\d{2}-\d{2}$/.test(value || "")) return null;
    const [y,m,d] = value.split("-").map(Number);
    const dt = new Date(y, m - 1, d);
    return dt.getFullYear() === y && dt.getMonth() === m - 1 && dt.getDate() === d ? dt : null;
  }
  function daysBetween(a, b) {
    const utcA = Date.UTC(a.getFullYear(), a.getMonth(), a.getDate());
    const utcB = Date.UTC(b.getFullYear(), b.getMonth(), b.getDate());
    return Math.round((utcB - utcA) / 86400000);
  }
  function escapeHTML(value) {
    return String(value ?? "").replace(/[&<>'"]/g, c => ({"&":"&amp;","<":"&lt;",">":"&gt;","'":"&#39;",'"':"&quot;"}[c]));
  }

  function cleanBloggerArtifacts(root) {
    if (!root || !document.createTreeWalker) return;
    const map = [[/(?:&amp;)?#39;?/g,"'"],[/(?:&amp;)?#183;?/g,"·"],[/(?:&amp;)?#215;?/g,"×"],[/(?:&amp;)?#8230;?/g,"…"],[/(?:&amp;)?#572;?/g,""]];
    const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, null);
    let node;
    while ((node = walker.nextNode())) {
      let value = node.nodeValue;
      map.forEach(([pattern,replacement]) => { value = value.replace(pattern,replacement); });
      if (value !== node.nodeValue) node.nodeValue = value;
    }
  }

  function setMessage(el, message, type = "error") {
    if (!el) return;
    el.textContent = message || "";
    el.dataset.type = type;
    el.hidden = !message;
  }
  function setResult(el, html) {
    if (!el) return;
    el.innerHTML = html;
    el.hidden = false;
  }
  function clearResult(el) {
    if (!el) return;
    el.innerHTML = "";
    el.hidden = true;
  }
  function bindNumericInput(input, { decimal = true } = {}) {
    if (!input) return;
    input.addEventListener("input", () => {
      let v = input.value.replace(/,/g, "");
      v = decimal ? v.replace(/[^0-9.\-]/g, "") : v.replace(/[^0-9\-]/g, "");
      const parts = v.split(".");
      if (parts.length > 2) v = parts.shift() + "." + parts.join("");
      input.value = v;
    });
  }
  function field(label, inputHTML, hint = "") {
    return `<div class="hm-calc-field"><label>${label}</label>${inputHTML}${hint ? `<p class="hm-calc-hint">${hint}</p>` : ""}</div>`;
  }
  function resultCard(title, value, details = "") {
    return `<section class="hm-calc-result-card" aria-live="polite"><p class="hm-calc-result-label">${escapeHTML(title)}</p><div class="hm-calc-result-value">${value}</div>${details ? `<div class="hm-calc-result-details">${details}</div>` : ""}</section>`;
  }
  function register(id, definition) {
    if (!id || !definition || typeof definition.render !== "function") throw new Error("Invalid calculator module: " + id);
    modules[id] = definition;
  }
  function mount(root, id, options = {}) {
    if (!root || !id) return;
    const mod = modules[id];
    if (!mod) throw new Error("Calculator module not loaded: " + id);
    if (mounted.has(root)) return;
    root.classList.add("hm-calc-widget");
    root.dataset.hmCalculatorMounted = "true";
    mod.render(root, api, options);
    cleanBloggerArtifacts(root);
    if (window.MutationObserver) {
      const observer = new MutationObserver(() => cleanBloggerArtifacts(root));
      observer.observe(root, { childList: true, subtree: true, characterData: true });
    }
    mounted.set(root, id);
  }
  function has(id) { return !!modules[id]; }

  const api = { register, mount, has, parseNumber, formatNumber, formatWon, localDateString, dateFromLocalInput, daysBetween, escapeHTML, cleanBloggerArtifacts, setMessage, setResult, clearResult, bindNumericInput, field, resultCard };
  w.HM_CALC = Object.assign(w.HM_CALC || {}, api);
})(window);
